
import numpy as np
import torch
"""This code is generated by ChatGPT 5.2!"""

def sample_minibatch(replaybuffer, batch_size: int, device: torch.device, gpu_buffer: bool):
    s, a, ns, r, terminated, truncated = replaybuffer.sample_batch_stacked(batch_size, replace=True)

    # ✅ FAST PATH: GPU-Replay liefert i.d.R. bereits CUDA float32 Tensoren
    if gpu_buffer and isinstance(s, torch.Tensor) and s.is_cuda:
        # nur falls dtype nicht float32 ist casten (meistens ist es schon float32)
        if s.dtype != torch.float32:  s = s.float()
        if a.dtype != torch.float32:  a = a.float()
        if ns.dtype != torch.float32: ns = ns.float()
        if r.dtype != torch.float32:  r = r.float()
        if terminated.dtype != torch.float32: terminated = terminated.float()
        if truncated.dtype != torch.float32:  truncated = truncated.float()

        # Shapes sind im GPU buffer bereits (B,1) für r/flags
        return s, a, ns, r, terminated, truncated

    # CPU / numpy path
    def to_torch(x):
        if isinstance(x, torch.Tensor):
            t = x
        else:
            t = torch.from_numpy(x) if isinstance(x, np.ndarray) else torch.as_tensor(x)
        # non_blocking bringt nur was wenn Quelle pinned ist – aber ok so.
        return t.to(device=device, dtype=torch.float32, non_blocking=True)

    state_batch      = to_torch(s)
    action_batch     = to_torch(a)
    next_state_batch = to_torch(ns)
    reward_batch     = to_torch(r)
    terminated_batch = to_torch(terminated)
    truncated_batch  = to_torch(truncated)

    # Normalize shapes to (B,1)
    if reward_batch.ndim == 1:
        reward_batch = reward_batch.view(-1, 1)
    if terminated_batch.ndim == 1:
        terminated_batch = terminated_batch.view(-1, 1)
    if truncated_batch.ndim == 1:
        truncated_batch = truncated_batch.view(-1, 1)

    return state_batch, action_batch, next_state_batch, reward_batch, terminated_batch, truncated_batch


def assert_batch_shapes(
    state_batch,
    action_batch,
    next_state_batch,
    reward_batch,
    terminated_batch,
    truncated_batch,
    batch_size,
    state_dim,
    action_dim,
    check_values: bool = False,  
):
    assert state_batch.ndim == 2
    assert next_state_batch.ndim == 2
    assert action_batch.ndim == 2

    if check_values:
        # Achtung: das synchronisiert auf GPU -> nur selten nutzen
        assert terminated_batch.min() >= 0 and terminated_batch.max() <= 1
        assert truncated_batch.min() >= 0 and truncated_batch.max() <= 1

    assert state_batch.shape == (batch_size, state_dim)
    assert next_state_batch.shape == (batch_size, state_dim)
    assert action_batch.shape == (batch_size, action_dim)
